    const m = mat1.length;
    const k = mat1[0].length;
    const n = mat2[0].length;
    const result = Array.from({ length: m }, () => Array.from({ length: n }, () => 0));
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < k; j++) {
